mapper.select:
/* selectMdocmaDoccateGroupList */
select
DOCCATE, DOCCTNM
from MDOCMA
where COMPKEY = #{userData.compkey}

	and WAREKEY = #{warekey}

group by DOCCATE, DOCCTNM

/* selectMdocmaDoccateList */
SELECT DOCCATE as COMBOVL
	 , DOCCTNM as COMBONM
  FROM MDOCMA
 WHERE COMPKEY = #{userData.compkey}

	and WAREKEY = #{warekey}


	and DOCCATE = #{doccate}


	and DOCTAT5 = #{doctat5}


	and DOCCATE in

		#{item}



   and DOCTAT5 in

   	 #{item}




		and DOUSEYN = #{douseyn}


		and DOUSEYN = 'Y'


group by DOCCATE, DOCCTNM
order by DOCCATE, DOCCTNM

/* selectMdocmaDoctypeList */
select DOCTYPE as COMBOVL
, DOCTYNM as COMBONM
, DOCCATE as DOCCATE
, DOCCTNM as DOCCTNM
, DOCTAT5 as DOCTAT5 
, WAREKEY as WAREKEY 
from MDOCMA
where COMPKEY = #{userData.compkey}

	and WAREKEY = #{warekey}


	and DOCCATE = #{doccate}


	and DOCTAT5 = #{doctat5}


	and DOCTYPE = #{doctype}


	and DOCCATE in

		#{item}



   and DOCTAT5 in

   	 #{item}



	and DOCTYPE in

		#{item}




		and DOUSEYN = #{douseyn}


		and DOUSEYN = 'Y'


group by WAREKEY, DOCTYPE, DOCTYNM, DOCCATE, DOCCTNM, DOCTAT5
order by DOCTYPE, DOCTYNM

/* selectMrscmaSelectBox */
select RSNCODE as COMBOVL
, RSNCDNM as COMBONM
from MRSCMA
where COMPKEY = #{userData.compkey}

	and WAREKEY = #{warekey}


	and DOCCATE = #{doccate}


	and DOCTYPE = #{doctype}



		and RSUSEYN = #{rsuseyn}


		and RSUSEYN = 'Y'



	and RSCATE1 = #{rscate1}

group by RSNCODE, RSNCDNM

/* selectWmr21MrscmaSelectBox */
select RSNCODE as COMBOVL
, RSNCDNM as COMBONM
, DOCCATE
, DOCTYPE
, WAREKEY
, RSNCODE as RCARSCD
, RSNCODE as PKRSNCD
from MRSCMA
where COMPKEY = #{userData.compkey}

	and WAREKEY = #{warekey}


	and DOCCATE = #{doccate}


	and DOCTYPE = #{doctype}



		and RSUSEYN = #{rsuseyn}


		and RSUSEYN = 'Y'



	and RSCATE1 = #{rscate1}

group by RSNCODE, RSNCDNM, DOCCATE, DOCTYPE
